import React, {useState} from 'react';

import classes from './quiz-display.module.css';

const QuizDisplay = (props) => {
    const question = props.questions;

    const [isCorrect, setIsCorrect] = useState(['white', 'white', 'white', 'white']);

    const shooseAnswerHandler = (correct, index) => {
        let newClass;
        let newCorrect = [...isCorrect];

        if (correct) {
            newClass = 'green';
        } else {
            newClass = 'red';
        }

        newCorrect[index] = newClass;

        setIsCorrect(newCorrect);

        setTimeout(() => {
            props.questionIndexUp(correct);
            setIsCorrect(['white', 'white', 'white', 'white']);
        }, 500);
    };

    return (
        <div className={classes['quiz-display']}>
            <div className={classes['quiz-display-question']}>{question.question}</div>
            <ul>
                <li className={classes[isCorrect[0]]} onClick={() => {shooseAnswerHandler(question.answers[0].correct, 0)}}>{question.answers[0].text}</li>
                <li className={classes[isCorrect[1]]} onClick={() => {shooseAnswerHandler(question.answers[1].correct, 1)}}>{question.answers[1].text}</li>
                <li className={classes[isCorrect[2]]} onClick={() => {shooseAnswerHandler(question.answers[2].correct, 2)}}>{question.answers[2].text}</li>
                <li className={classes[isCorrect[3]]} onClick={() => {shooseAnswerHandler(question.answers[3].correct, 3)}}>{question.answers[3].text}</li>
            </ul>
        </div>
    );
};

export default QuizDisplay;