import React, {useState} from 'react';

import QuizDisplay from './components/quiz-display/quiz-display';
import Result from './components/result/result';

import questions from './data/questions';

const App = () => {
  const [questionIndex, setQuestionIndex] = useState(0);
  const [rightAnswers, setRightAnswers] = useState(0);

  const questionIndexUp = (correct) => {
    if (correct) {
      setRightAnswers((prev) => {
        return prev + 1;
      });
    };

    setQuestionIndex((prev) => {
      return prev + 1;
    });
  };

  let content;

  if (questionIndex === questions.length) {
    content = <Result amountRightAnswers={rightAnswers}/>;
  } else {
    content = <QuizDisplay questions={questions[questionIndex]} questionIndexUp={questionIndexUp}/>;
  };

  return (
    <>
      {content}
    </>
  );
};

export default App;